  <title>Sistema Jurídico Próprio - Proposta</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@600;700&family=Manrope:wght@400;500;600;700;800&display=swap');
    :root{--primary:#4b1e28;--secondary:#2f1118;--bg:#f7f1ea;--surface:#fffdfa;--surface-alt:#f1e8df;--surface-strong:#e2d3c2;--text:#1c1718;--text-body:#4f4346;--muted:#7f6f72;--border:#d8c8b7;--accent:#c6a76a;--accent-light:#eadfcb;--accent-soft:#b89452;--highlight:#dfc189;--success:#6f8a62;--success-light:#e2eadc;--warning:#b78943;--warning-light:#f3e6d2;--danger:#8b4a52;--danger-light:#f1dfe1;--shadow:0 8px 24px rgba(45,17,24,.08);--shadow-lg:0 18px 42px rgba(45,17,24,.14)}
