    .mockup--kanban .mockup__content{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.mockup__column{padding:8px;border-radius:8px;background:var(--surface-alt)} .mockup__column-header{margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid var(--border);font:800 9px 'Manrope',sans-serif;letter-spacing:.08em;text-transform:uppercase;color:var(--muted)}
    .mockup__task{margin-bottom:6px;padding:6px;border-radius:5px;border:1px solid var(--border);background:var(--surface);font-size:9px}.mockup__task:last-child{margin-bottom:0}.mockup__task-title{margin-bottom:4px;font-weight:700;color:var(--text)} .mockup__task-meta{display:flex;justify-content:space-between;align-items:center}.mockup__task-avatar{width:14px;height:14px;border-radius:50%;display:flex;align-items:center;justify-content:center;background:var(--accent);color:#fff;font-size:6px;font-weight:800}
    .mockup__task-priority{width:5px;height:5px;border-radius:50%}.mockup__task-priority--high{background:var(--danger)}.mockup__task-priority--medium{background:var(--warning)}.mockup__task-priority--low{background:var(--success)}
    .mockup__docs,.mockup__notif-list{display:flex;flex-direction:column;gap:6px}.mockup__doc,.mockup__notif{display:flex;gap:8px;align-items:flex-start;padding:8px;border-radius:8px;background:var(--surface-alt)} .mockup__doc-icon{width:22px;height:22px;border-radius:6px;display:flex;align-items:center;justify-content:center;font:800 9px 'Manrope',sans-serif} .mockup__doc-icon--pdf{background:#fce4e4;color:#c53030}.mockup__doc-icon--img,.mockup__doc-icon--doc{background:#e4f0fc;color:#2b6cb0}
    .mockup__doc-info{flex:1}.mockup__doc-name,.mockup__notif-title{font-size:10px;font-weight:700;color:var(--text)} .mockup__doc-meta,.mockup__notif-text{font-size:9px;color:var(--muted)} .mockup__doc-status{width:7px;height:7px;border-radius:50%;background:var(--success)} .mockup__doc-status--pending{background:var(--warning)}
    .mockup__timeline{display:flex;gap:6px;padding-top:8px;border-top:1px solid var(--border)} .mockup__timeline-item{flex:1;text-align:center}.mockup__timeline-dot{width:6px;height:6px;margin:0 auto 4px;border-radius:50%;background:var(--border)} .mockup__timeline-dot--active{background:var(--success)} .mockup__timeline-dot--current{background:var(--warning)} .mockup__timeline-label{font-size:8px;color:var(--muted)}
    .mockup--search .mockup__content{flex-direction:column;gap:10px}.mockup__search-bar{display:flex;gap:8px;align-items:center;padding:8px 10px;border:1px solid var(--border);border-radius:8px;background:var(--surface-alt)} .mockup__search-bar input{width:100%;border:none;background:transparent;color:var(--text);font-size:11px}.mockup__search-filters{display:flex;gap:6px;flex-wrap:wrap}.mockup__filter{padding:3px 8px;border-radius:999px;border:1px solid var(--border);background:var(--surface);font-size:9px;color:var(--text-body)} .mockup__filter--active{background:var(--primary);border-color:var(--primary);color:#fff}
    .mockup__notif{border-left:2px solid var(--accent)} .mockup__notif-icon{width:18px;height:18px;flex-shrink:0;border-radius:5px;display:flex;align-items:center;justify-content:center;background:var(--accent-light);color:var(--primary);font-size:11px} .mockup__notif-time{font-size:8px;color:var(--muted);margin-top:2px}
    .mockup__table{width:100%;border-collapse:collapse;font-size:10px}.mockup__table th{padding:6px 8px;text-align:left;border-bottom:1px solid var(--border);background:var(--surface-alt);color:var(--text-body);font:800 9px 'Manrope',sans-serif;letter-spacing:.08em;text-transform:uppercase}.mockup__table td{padding:6px 8px;border-bottom:1px solid var(--surface-strong);color:var(--text-body)} .mockup__table tr:last-child td{border-bottom:none}
    .mockup__avatar-group{display:flex}.mockup__avatar{width:20px;height:20px;margin-left:-6px;border-radius:50%;border:2px solid var(--surface);display:flex;align-items:center;justify-content:center;color:#fff;font:800 8px 'Manrope',sans-serif}.mockup__avatar:first-child{margin-left:0}
    .modulo__help{margin-top:26px;padding:20px;border-radius:14px;border-left:3px solid var(--accent-soft);background:linear-gradient(180deg,rgba(234,223,203,.64),rgba(241,232,223,.95))}.modulo__help p{font-size:14px;color:var(--primary);line-height:1.55}
    .fechamento__decision-grid{margin-top:18px}.fechamento__decision-card{padding:18px;border-radius:14px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.12)} .fechamento__decision-card strong{display:block;margin-bottom:8px;font:800 10px 'Manrope',sans-serif;letter-spacing:.14em;text-transform:uppercase;color:var(--highlight)}
    .fechamento__header{text-align:center;margin-bottom:30px}.fechamento__escopo-card{text-align:center}.fechamento__prox{padding:28px;border-radius:16px;background:rgba(255,253,250,.8);border:1px solid var(--border);text-align:center}.fechamento__prox h3{font-size:30px;margin-bottom:8px}.fechamento__prox p{font-size:15px;color:var(--text-body);line-height:1.7}
