    @media (max-width:900px){.page{padding:32px}.capa{padding:40px 32px}.capa__title{font-size:42px}.capa__subtitle,.resumo__impact-quote,.fechamento__decision h3{font-size:28px}.capa__stakes,.resumo__grid,.resumo__module-list,.submodulo,.modulo__help,.fechamento__decision-grid,.fechamento__escopo,.mockup--kanban .mockup__content{grid-template-columns:1fr}.mockup__content,.modulo__header,.page-footer{flex-direction:column}.mockup__sidebar{width:100%}.modulo__header,.page-footer{align-items:flex-start}}
    @media print{body{background:#fff}.page{margin:0;max-width:100%;box-shadow:none}}
  </style>
</head>
